import{_ as t,o as i,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Branch Attribution Explained","description":"","frontmatter":{"title":"Branch Attribution Explained","slug":"branch-attribution-explained"},"headers":[],"relativePath":"marketer-hub/branch-attribution-explained.md","filePath":"marketer-hub/branch-attribution-explained.md"}'),r={name:"marketer-hub/branch-attribution-explained.md"};function s(o,e,c,l,h,d){return i(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="how-branch-attribution-works" tabindex="-1">How Branch attribution works <a class="header-anchor" href="#how-branch-attribution-works" aria-label="Permalink to &quot;How Branch attribution works&quot;">​</a></h2><p>Branch determines which marketing touchpoint motivated a user to install or open an app, then attributes that action back to the source using multiple attribution methods prioritized by accuracy.</p><h3 id="understanding-attribution" tabindex="-1">Understanding attribution <a class="header-anchor" href="#understanding-attribution" aria-label="Permalink to &quot;Understanding attribution&quot;">​</a></h3><p>Attribution is the process of connecting user actions across different environments—typically from clicking a link in a web browser to installing or opening an app on a mobile device. This connection is essential for understanding which marketing efforts drive results and optimizing campaigns accordingly.</p><p>Branch uses multiple attribution methods to make these connections, always prioritizing the most accurate method available for each situation. The key differentiator in attribution accuracy is whether Branch can make a <strong>deterministic match</strong> (100% certain) or must rely on <strong>probabilistic matching</strong> (high confidence based on statistical modeling).</p><h4 id="the-match-guarantee-flag" tabindex="-1">The match guarantee flag <a class="header-anchor" href="#the-match-guarantee-flag" aria-label="Permalink to &quot;The match guarantee flag&quot;">​</a></h4><p>When Branch achieves 100% certainty about an attribution match, the deep link data includes the flag <code>+match_guaranteed=true</code>. This flag is critical for sensitive use cases:</p><ul><li><strong>Auto-login flows:</strong> Only log users in automatically when matches are guaranteed</li><li><strong>Personal data display:</strong> Only show personalized information with certain matches</li><li><strong>High-value actions:</strong> Gate critical actions on match certainty</li></ul><p>Mobile app logic should parse this flag from the SDK initialization callback and proceed with sensitive actions only when the value is <code>true</code>.</p><h4 id="ios-14-and-match-certainty" tabindex="-1">iOS 14+ and match certainty <a class="header-anchor" href="#ios-14-and-match-certainty" aria-label="Permalink to &quot;iOS 14+ and match certainty&quot;">​</a></h4><p>Post-iOS 14, Apple&#39;s App Tracking Transparency framework limits access to the IDFA (Identifier for Advertisers) unless users explicitly opt in. As a result, <code>+match_guaranteed</code> is usually <code>false</code> on new install events, making deterministic attribution more challenging. This shift has made solutions like NativeLink™ increasingly important for maintaining attribution accuracy on iOS.</p><h2 id="attribution-methods-by-accuracy" tabindex="-1">Attribution methods by accuracy <a class="header-anchor" href="#attribution-methods-by-accuracy" aria-label="Permalink to &quot;Attribution methods by accuracy&quot;">​</a></h2><h3 id="deterministic-attribution-100-accuracy" tabindex="-1">Deterministic attribution (100% accuracy) <a class="header-anchor" href="#deterministic-attribution-100-accuracy" aria-label="Permalink to &quot;Deterministic attribution (100% accuracy)&quot;">​</a></h3><p>Deterministic methods provide absolute certainty about attribution matches. These methods rely on passing unique identifiers or using platform-provided mechanisms that create direct, verifiable connections between clicks and app sessions.</p><p>Deterministic methods include:</p><ul><li>Direct deep linking</li><li>iOS NativeLink</li><li>Install referrers</li><li>Device ID matching across the Branch platform</li><li>Platform integrations</li><li>SKAdNetwork</li></ul><h4 id="direct-deep-linking" tabindex="-1">Direct deep linking <a class="header-anchor" href="#direct-deep-linking" aria-label="Permalink to &quot;Direct deep linking&quot;">​</a></h4><p><strong>Use case:</strong> Attributing users when the app is already installed on their device.</p><p><strong>How it works:</strong> When a user with the app already installed clicks a Branch link configured with the app&#39;s URI scheme (e.g., <code>myapp://</code>) or Universal/App Links, the link opens the app immediately. Branch passes a unique click identifier through the deep link—for example, <code>myapp://open?link_click_id=123456</code>. The Branch SDK parses this identifier and sends it back to Branch servers, which return the complete data dictionary associated with that specific link click.</p><p><strong>Why it&#39;s deterministic:</strong> The identifier passes directly through the app itself in a closed loop. There&#39;s no ambiguity—the click ID that went into the link is the same ID that comes out in the app.</p><p><strong>Platforms:</strong> iOS, Android, and any platform supporting deep linking protocols.</p><h4 id="ios-nativelinktm-deferred-deep-linking" tabindex="-1">iOS NativeLink™ (deferred deep linking) <a class="header-anchor" href="#ios-nativelinktm-deferred-deep-linking" aria-label="Permalink to &quot;iOS NativeLink™ (deferred deep linking)&quot;">​</a></h4><p><strong>Use case:</strong> Attributing new iOS app installs with guaranteed accuracy despite iOS 14+ privacy restrictions.</p><p><strong>The challenge:</strong> Traditional deferred deep linking (connecting a click before app install to the first app open after install) became problematic with iOS 15 and iCloud+ Private Relay, which obscures IP addresses and other matching signals.</p><p><strong>How it works:</strong> NativeLink™ uses the iOS pasteboard (clipboard) to pass attribution data across the install boundary:</p><ol><li>User clicks a Branch link and sees a Deepview (preview page)</li><li>When the user taps the main call-to-action, attribution data is written to the device pasteboard</li><li>User proceeds to the App Store and installs the app</li><li>On first launch, the Branch SDK reads the pasteboard data</li><li>Match is guaranteed: <code>+match_guaranteed=true</code></li></ol><p><strong>Why it&#39;s deterministic:</strong> Attribution data is physically passed through the device&#39;s pasteboard, creating a direct connection that doesn&#39;t rely on matching signals or IDs.</p><p><strong>Implementation note:</strong> Requires specific setup documented in Branch&#39;s developer documentation. Once enabled, it provides the most reliable attribution for new iOS installs in the post-iOS 14 era.</p><h4 id="install-referrers-android" tabindex="-1">Install referrers (Android) <a class="header-anchor" href="#install-referrers-android" aria-label="Permalink to &quot;Install referrers (Android)&quot;">​</a></h4><p><strong>Use case:</strong> Attributing Android app installs from supported app stores.</p><p><strong>How it works:</strong> Android app stores provide a built-in attribution mechanism called the install referrer. When a user clicks an ad or link that leads to an app store:</p><ol><li>The advertiser delivers content with an install referrer to the app store</li><li>User clicks and is directed to the app store</li><li>User installs the app</li><li>The app store writes the install referrer data to an API</li><li>On first launch, the Branch SDK queries the app store&#39;s API and retrieves the referrer</li><li>The install is attributed back to the source with 100% certainty</li></ol><p><strong>Supported app stores:</strong></p><ul><li>Google Play Store (app version 8.3.73+)</li><li>Huawei AppGallery (EMUI v3.0+, HMS Core v2.6.5+)</li><li>Samsung Galaxy Store (v4.5.20.1+)</li><li>Xiaomi GetApps (v22.6.0.0+)</li></ul><p><strong>Why it&#39;s deterministic:</strong> The app store itself confirms where the install came from through its official API, eliminating any ambiguity.</p><p><strong>Requirements:</strong> Apps must use an up-to-date Branch Android SDK with proper dependencies implemented to support install referrer collection.</p><h4 id="device-id-matching-across-the-branch-platform" tabindex="-1">Device ID matching across the Branch platform <a class="header-anchor" href="#device-id-matching-across-the-branch-platform" aria-label="Permalink to &quot;Device ID matching across the Branch platform&quot;">​</a></h4><p><strong>Use case:</strong> Recognizing users who have previously interacted with any Branch-powered app or link.</p><p><strong>How it works:</strong> As users engage with apps and websites where the Branch SDK is integrated, Branch&#39;s attribution engine builds connections between browser cookies (collected on Branch link clicks) and device identifiers (collected when users engage with apps).</p><p>When a user clicks a Branch link, if Branch has previously seen that user and successfully paired their browser cookie to a device ID, Branch can deterministically attribute that user immediately. This means when they install an app and a device ID becomes available, Branch knows with 100% certainty this is the same user who clicked the Branch link.</p><p><strong>The network effect:</strong> This method improves over time as more users interact with Branch-powered apps. Each successful browser-to-app connection strengthens the attribution engine&#39;s ability to recognize users across the platform. With hundreds of millions of users clicking Branch Links, the platform continually makes new connections that benefit all Branch customers.</p><p><strong>Why it&#39;s deterministic:</strong> Branch has verified the connection between this specific browser cookie and device ID through previous first-party interactions. When both identifiers appear again, Branch can definitively say they belong to the same user.</p><p><strong>Privacy consideration:</strong> This method relies on first-party data collected through direct user interactions with Branch-integrated apps and links, not third-party tracking.</p><h4 id="platform-integrations-self-attributing-networks" tabindex="-1">Platform integrations (self-attributing networks) <a class="header-anchor" href="#platform-integrations-self-attributing-networks" aria-label="Permalink to &quot;Platform integrations (self-attributing networks)&quot;">​</a></h4><p><strong>Use case:</strong> Attributing users from major advertising platforms with direct confirmation.</p><p><strong>How it works:</strong> Branch maintains direct integrations with major platforms including Apple, Facebook, Google, Twitter, and Snap. These platforms can definitively confirm whether a specific user engaged with an ad on their platform.</p><p>When an app install occurs, Branch compares the touchpoints it has observed (from Branch Links) against engagement data provided directly by these platforms. This allows Branch to attribute with greater certainty across both organic and paid channels.</p><p><strong>Why it&#39;s deterministic:</strong> The platforms themselves verify user engagement, providing authoritative confirmation that removes uncertainty from the attribution decision.</p><h4 id="skadnetwork" tabindex="-1">SKAdNetwork <a class="header-anchor" href="#skadnetwork" aria-label="Permalink to &quot;SKAdNetwork&quot;">​</a></h4><p><strong>Use case:</strong> Campaign-level attribution for iOS 14+ in compliance with Apple&#39;s privacy framework.</p><p><strong>How it works:</strong> SKAdNetwork is Apple&#39;s privacy-preserving attribution framework. Rather than providing user-level data, Apple verifies and reports attribution at the campaign level. When a conversion occurs, Apple cryptographically signs the attribution data, guaranteeing its accuracy.</p><p><strong>Limitations:</strong> SKAdNetwork doesn&#39;t provide user-level insights—you can&#39;t track individual user journeys. However, all app store installs are verified by Apple with 100% certainty at the campaign level.</p><p><strong>Why it&#39;s deterministic:</strong> Apple itself validates and confirms the attribution, making the campaign-level data completely reliable even though it&#39;s aggregated.</p><hr><h3 id="probabilistic-attribution-high-confidence" tabindex="-1">Probabilistic attribution (high confidence) <a class="header-anchor" href="#probabilistic-attribution-high-confidence" aria-label="Permalink to &quot;Probabilistic attribution (high confidence)&quot;">​</a></h3><p>When deterministic methods aren&#39;t available, Branch uses sophisticated modeling to make high-confidence attribution decisions. These methods analyze patterns and metadata to statistically determine matches, showing <code>+match_guaranteed=false</code> because they&#39;re predictive rather than definitive.</p><h4 id="predictive-modeling-engine" tabindex="-1">Predictive modeling engine <a class="header-anchor" href="#predictive-modeling-engine" aria-label="Permalink to &quot;Predictive modeling engine&quot;">​</a></h4><p><strong>Use case:</strong> Attributing users when device IDs aren&#39;t available but contextual signals are strong.</p><p><strong>How it works:</strong> Branch&#39;s predictive modeling engine leverages machine learning trained on hundreds of millions of user interactions. When a user clicks a Branch link, Branch collects their browser cookie along with associated device metadata like IP addresses and user agents. Even if their device ID is unavailable, Branch can pair the browser cookie to this metadata and use it for probabilistic attribution.</p><p>When the app opens, Branch compares the app&#39;s device metadata against the browser metadata from recent clicks. If the patterns align strongly enough—same IP, similar timing, matching device characteristics—Branch can attribute with high confidence even without a device ID match.</p><p><strong>Why it&#39;s high confidence:</strong> With hundreds of millions of data points, Branch&#39;s models can identify patterns that are statistically very unlikely to represent different users. The probability of two different users having identical IP addresses, user agents, device models, OS versions, and timing within the same geographic area is extremely low.</p><p><strong>Accuracy improvement:</strong> As more users interact with Branch-powered apps, the predictive models continuously improve, providing greater attribution accuracy when connecting app behaviors back to browser touches.</p><h4 id="browser-to-app-fingerprinting" tabindex="-1">Browser-to-app fingerprinting <a class="header-anchor" href="#browser-to-app-fingerprinting" aria-label="Permalink to &quot;Browser-to-app fingerprinting&quot;">​</a></h4><p><strong>Use case:</strong> Fallback attribution when no other mechanism is available.</p><p><strong>What Branch collects:</strong></p><ul><li>IP address (including IPv6)</li><li>Operating system and version</li><li>Device model</li><li>User agent string</li><li>Browser information</li></ul><p><strong>How it works:</strong> Branch collects limited device-level information in two moments—when a user clicks a Branch link in their browser, and again when they open the app. Branch then compares these &quot;fingerprints&quot; to find unique matches within specific time windows.</p><p>The key is uniqueness combined with timing. If enough data points align and the timing is right (click followed shortly by app open), Branch can say with high probability that it&#39;s the same user.</p><p><strong>Example scenario:</strong> A user with a specific phone model, running a particular OS version, on a residential IP address in a specific city, clicks a link at 2:00 PM and opens the app at 2:03 PM. If no other clicks from that exact configuration occurred in that timeframe, it&#39;s extremely probable they&#39;re the same person.</p><p><strong>Privacy compliance:</strong> Branch collects only limited, non-personal data as outlined in Branch&#39;s Privacy Policy. This data cannot identify individuals but can create sufficiently unique fingerprints for attribution purposes.</p><h3 id="additional-attribution-techniques" tabindex="-1">Additional attribution techniques <a class="header-anchor" href="#additional-attribution-techniques" aria-label="Permalink to &quot;Additional attribution techniques&quot;">​</a></h3><h4 id="custom-user-ids" tabindex="-1">Custom user IDs <a class="header-anchor" href="#custom-user-ids" aria-label="Permalink to &quot;Custom user IDs&quot;">​</a></h4><p><strong>Use case:</strong> Improving attribution accuracy with app-specific anonymous identifiers.</p><p><strong>How it works:</strong> Branch&#39;s mobile and web SDKs allow developers to assign custom user IDs to web and app events. When a user interacts with both web and app while using the same custom ID, Branch can use this as an additional signal to augment attribution.</p><p><strong>Important restriction:</strong> Developers must never use personally identifiable information (PII) in these fields. Custom IDs should be anonymous identifiers specific to the app&#39;s internal user system.</p><p><strong>Benefit:</strong> These IDs provide another data point that can strengthen attribution confidence, especially for apps with strong cross-platform user bases.</p><h4 id="web-sdk-attribution" tabindex="-1">Web SDK attribution <a class="header-anchor" href="#web-sdk-attribution" aria-label="Permalink to &quot;Web SDK attribution&quot;">​</a></h4><p><strong>Use case:</strong> Tracking web-to-app user journeys and attributing mobile web conversions.</p><p><strong>How it works:</strong> The Branch Web SDK must be implemented across multiple pages (homepage, product pages, etc.) to ensure proper measurement. When a user lands on a page with the SDK initialized, it makes requests to Branch endpoints (<code>v1/open</code> and <code>v1/pageview</code>). A cookie is stored in local storage containing data used for attribution and, if applicable, displaying Journeys banners.</p><p><strong>Click-to-event matching:</strong> Using Branch&#39;s predictive modeling, the Web SDK can create matches between link clicks and subsequent web events. When a user clicks a Branch link, the system observes characteristics like IP and user agent. Later, when that user&#39;s web session contains similar characteristics, Branch can probabilistically tie subsequent web events back to the original click.</p><p><strong>ITP considerations:</strong> Safari&#39;s Intelligent Tracking Prevention (ITP) limits data storage in localStorage and sessionStorage, potentially causing the Web SDK to create new browser IDs when data is wiped. However, the impact is minimal because Branch&#39;s Link Graph is built on first-party interactions with deep links. The system can reconnect identity fragments in a privacy-friendly way as ITP creates them. Even with ITP&#39;s 7-day cap on script-writable storage, Branch maintains attribution accuracy through its first-party data approach.</p><h2 id="special-considerations-and-platform-specific-behavior" tabindex="-1">Special considerations and platform-specific behavior <a class="header-anchor" href="#special-considerations-and-platform-specific-behavior" aria-label="Permalink to &quot;Special considerations and platform-specific behavior&quot;">​</a></h2><h3 id="ios-privacy-changes-and-att" tabindex="-1">iOS privacy changes and ATT <a class="header-anchor" href="#ios-privacy-changes-and-att" aria-label="Permalink to &quot;iOS privacy changes and ATT&quot;">​</a></h3><p>Apple&#39;s App Tracking Transparency framework fundamentally changed mobile attribution by requiring apps to request permission before accessing the IDFA. When Limit Ad Tracking is enabled or ATT permission is denied, no IDFA is available on the device.</p><p><strong>Branch&#39;s response:</strong></p><ul><li>For users without IDFA, Branch doesn&#39;t make calls to self-attributing networks (Twitter, Facebook, Google, Snap) using IDFA</li><li>Branch uses IDFV (Identifier for Vendor) instead when available</li><li>The flag doesn&#39;t explicitly affect attribution—it&#39;s passed through to ad networks who decide whether to target the user</li><li>NativeLink™ provides a deterministic alternative that doesn&#39;t rely on IDFA</li></ul><h3 id="safari-26-and-ios-version-detection" tabindex="-1">Safari 26 and iOS version detection <a class="header-anchor" href="#safari-26-and-ios-version-detection" aria-label="Permalink to &quot;Safari 26 and iOS version detection&quot;">​</a></h3><p><strong>The issue:</strong> Safari 26 on iOS/iPadOS/visionOS freezes the OS token in the user agent string at iPhone OS 18_6, regardless of the actual OS version. This means Branch receives iOS 18.6 as the OS version even for devices running iOS 26.</p><p><strong>Branch&#39;s solution (no SDK update required):</strong></p><ul><li>If <code>os_version</code> is present and shows iOS 18.6 or higher, Branch uses the browser version for attribution</li><li>If <code>os_version</code> is present but <code>browser_version</code> is missing, Branch falls back to <code>os_version</code></li><li>If neither is present, matching would not succeed and probabilistic attribution won&#39;t work</li></ul><p><strong>Impact areas:</strong> This affects deferred deep linking, matching and attribution logic, and analytics reporting by OS version.</p><p><strong>Recommended approach:</strong> For best results with iOS 26 users, implement NativeLink™, which bypasses these user agent limitations entirely.</p><h3 id="customizing-match-criteria-for-strictness" tabindex="-1">Customizing match criteria for strictness <a class="header-anchor" href="#customizing-match-criteria-for-strictness" aria-label="Permalink to &quot;Customizing match criteria for strictness&quot;">​</a></h3><p><strong>The concern:</strong> In probabilistic matching, there&#39;s a theoretical risk that different users might have identical anonymous metadata (same device model, IP address, timing, etc.), leading to incorrect attribution.</p><p><strong>The solution:</strong> In the Dashboard&#39;s Link Settings page under advanced options, set Match Type to &quot;Unique.&quot; This tells Branch to make no attribution decision if two identical sets of metadata are under consideration—essentially prioritizing precision over recall.</p><p><strong>Trade-off:</strong> This setting is more conservative and will result in fewer attributed installs, but those that are attributed will have even higher confidence.</p><h3 id="attribution-windows-and-lookback-periods" tabindex="-1">Attribution windows and lookback periods <a class="header-anchor" href="#attribution-windows-and-lookback-periods" aria-label="Permalink to &quot;Attribution windows and lookback periods&quot;">​</a></h3><p><strong>What they are:</strong> Attribution windows define how long after a click or impression Branch can attribute a downstream conversion (like an install or in-app event).</p><p><strong>Example:</strong> With a 7-day click attribution window, if a user clicks a link on Monday and installs the app the following Tuesday (6 days later), Branch attributes the install. If they install 8 days later, Branch considers it organic.</p><p><strong>Customization:</strong> Attribution windows can be modified for each integration through the Dashboard. This allows alignment with partner agreements and campaign-specific requirements.</p><p><strong>Standard defaults:</strong></p><ul><li>Click attribution: 7 days (industry standard)</li><li>View attribution: 1 day</li><li>Re-attribution: 90 days</li></ul><h3 id="desktop-impression-tracking-and-view-through-attribution" tabindex="-1">Desktop impression tracking and view-through attribution <a class="header-anchor" href="#desktop-impression-tracking-and-view-through-attribution" aria-label="Permalink to &quot;Desktop impression tracking and view-through attribution&quot;">​</a></h3><p><strong>Impression recording:</strong> Branch records impressions on both desktop and mobile platforms.</p><p><strong>View-through attribution (VTA) limitation:</strong> VTA is only applicable for mobile because it requires device identifiers (AAID for Android, IDFA for iOS). Desktop conversions recorded without mobile device identifiers are counted as organic, as there&#39;s no way to deterministically or probabilistically connect the desktop impression to a mobile app install.</p><h3 id="user-location-tracking" tabindex="-1">User location tracking <a class="header-anchor" href="#user-location-tracking" aria-label="Permalink to &quot;User location tracking&quot;">​</a></h3><p><strong>How it works:</strong> Branch determines user location using signals from the SDK combined with IP address geolocation.</p><p><strong>Available in:</strong></p><ul><li>Dashboard: Use &quot;Country,&quot; &quot;Geo,&quot; or &quot;Region&quot; to compare by location</li><li>Data exports: Location information appears in log-level exports</li></ul><h2 id="attribution-methodology-summary" tabindex="-1">Attribution methodology summary <a class="header-anchor" href="#attribution-methodology-summary" aria-label="Permalink to &quot;Attribution methodology summary&quot;">​</a></h2><p>Branch&#39;s attribution approach prioritizes accuracy and transparency by using the best available method for each situation. The hierarchy flows from deterministic methods that provide guaranteed matches to sophisticated probabilistic models when direct identification isn&#39;t possible. This multi-method approach, combined with the network effects of hundreds of millions of users on the Branch platform, delivers reliable attribution across diverse scenarios while respecting user privacy and platform restrictions.</p><p>For sensitive use cases, always check the <code>+match_guaranteed</code> flag before taking action on attribution data. For iOS apps facing attribution challenges post-iOS 14, implementing NativeLink™ provides the most reliable path to deterministic attribution without depending on opt-in tracking permissions.</p>',112)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
